import numpy as np
import numpy as up
import matplotlib.pyplot as plt
data=""
import matplotlib
matplotlib.use('Agg')  # 使用非交互式后端
import matplotlib.pyplot as plt
import numpy as np

# 您的数据
bits = np.array(list(data), dtype=int)
size = int(len(bits) ** 0.5)
img = bits[:size*size].reshape((size, size))
img = np.flipud(img)

plt.figure(figsize=(10, 10))
plt.imshow(img, cmap='gray', interpolation='nearest')
plt.axis('off')
plt.savefig("fixed_qr.png", dpi=300, bbox_inches='tight', pad_inches=0)
print("二维码已成功保存为 fixed_qr.png")
